let body = $json.body ?? $json;
if (typeof body === 'string') {
  try {
    body = JSON.parse(body);
  } catch {
    throw new Error('Invalid JSON in webhook body');
  }
}

const topic = body.topic?.toString().trim();
if (!topic) {
  throw new Error('Missing required field: topic');
}

const audience = body.audience?.toString().trim() || 'Founders, hiring managers, and product teams evaluating serious AI execution talent';
const tone = body.tone?.toString().trim() || 'Sharp, credible, implementation-first, and insight-dense';
const wordCount = Number(body.wordCount ?? 1400);
const cta = body.cta?.toString().trim() || 'The gap between demo AI and production AI is not tooling. It is execution discipline. Teams that understand this will ship faster, break less, and win more.';
const goal = body.goal?.toString().trim() || 'Show the difference between systems that demo well and systems that survive production.';
const proofPoints = body.proofPoints?.toString().trim() || 'I have built agentic systems that generate, validate, and package content across blog and social in a single pipeline with failure isolation, structured outputs, and retry logic.';
const systemExample = body.systemExample?.toString().trim() || 'User input -> topic normalizer -> planner -> section generator -> validation layer -> metadata formatter -> output API. Validation checks length, duplication, structure, and tone alignment. If validation fails, regenerate only the weak section. If retries fail, fall back to a safe response template.';

return [{
  json: {
    topic,
    audience,
    tone,
    wordCount: Number.isFinite(wordCount) ? Math.max(900, Math.min(3200, wordCount)) : 1400,
    cta,
    goal,
    proofPoints,
    systemExample,
    requestedAt: new Date().toISOString()
  }
}];

const topic = $json.topic;
const audience = $json.audience;
const tone = $json.tone;
const wordCount = Number($json.wordCount ?? 1400);
const goal = $json.goal;
const proofPoints = $json.proofPoints;
const systemExample = $json.systemExample;

const searchQueries = [
  `${topic}`,
  `${topic} implementation playbook`,
  `${topic} failure handling architecture`,
  `${topic} state management patterns`,
  `${topic} production workflow case study`
];

const outline = [
  {
    section: 'The Market Shift',
    bullets: [
      `Open with a sharp hook about why ${topic} matters right now`,
      `Frame the opportunity and urgency for ${audience}`
    ]
  },
  {
    section: 'Why Most Teams Still Ship Demo-Grade AI',
    bullets: [
      'Show how shallow orchestration, weak validation, and prompt-only thinking fail in production',
      'Introduce the idea that most pipelines fail at validation, not generation'
    ]
  },
  {
    section: 'A Real System Mental Model',
    bullets: [
      `Use this architecture as the grounding example: ${systemExample}`,
      'Explain how agents communicate, where state lives, and where reliability checks sit'
    ]
  },
  {
    section: 'Failure Handling And Retry Logic',
    bullets: [
      'Describe partial regeneration, retry limits, and safe fallback behavior',
      'Call out latency versus quality as the real production trade-off'
    ]
  },
  {
    section: 'Proof Of Capability',
    bullets: [
      `Weave this proof in naturally: ${proofPoints}`,
      `Tie the article back to this hiring and client outcome: ${goal}`
    ]
  },
  {
    section: 'Closing Takeaways',
    bullets: [
      'Close with authority, not a sales pitch',
      'End on execution discipline and why it compounds team advantage'
    ]
  }
];

const angle = `${tone} article for ${audience} that reads like a strong operator showing real system design, failure handling, and business credibility in about ${wordCount} words.`;
const compactTopic = topic.replace(/\s+/g, ' ').trim();
const hookOptions = [
  `Most ${compactTopic} projects look impressive in demos. They break when production pressure shows up.`,
  `The hard part of ${compactTopic} is not generation. It is building a system that survives production.`,
  `Most teams think ${compactTopic} is a tooling problem. It is usually a structure problem.`
];
const hook = hookOptions[compactTopic.length % hookOptions.length];
const architectureLine = systemExample.includes('->')
  ? systemExample.split('.').map((part) => part.trim()).filter(Boolean)[0]
  : 'Input -> Planner -> Generator -> Validator -> Formatter -> Output';
const architectureSnapshot = `${architectureLine}\nFallback path: Validation fail -> Regenerate weak section only -> Retry cap -> Safe template response`;

return [{
  json: {
    search_queries: searchQueries,
    angle,
    hook,
    architectureSnapshot,
    outline,
    sources_note: 'Planner generated locally in n8n to preserve workflow reliability while producing a stronger content structure.'
  }
}];

let plan;

if (Array.isArray($json.search_queries) && Array.isArray($json.outline)) {
  plan = $json;
} else {
  const raw = ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('') || '{}';
  try {
    plan = JSON.parse(raw);
  } catch {
    plan = {
      search_queries: [],
      angle: 'Practical breakdown with real implementation notes',
      outline: [
        { section: 'Introduction', bullets: ['Context and problem statement'] },
        { section: 'Core Workflow', bullets: ['Step-by-step implementation details'] },
        { section: 'Conclusion', bullets: ['Actionable next steps'] }
      ],
      sources_note: 'No external sources parsed from planner output.'
    };
  }
}

return [{ json: { ...$item(0).$node['Normalize Input'].json, plan } }];

const draftMarkdown = typeof $json.draftMarkdown === 'string'
  ? $json.draftMarkdown
  : ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('');
if (!draftMarkdown.trim()) {
  throw new Error('Writer step returned empty content');
}

return [{
  json: {
    ...$item(0).$node['Parse Plan'].json,
    draftMarkdown
  }
}];

const source = $item(0).$node['Collect Draft'].json;
const topic = source.topic ?? 'Untitled';
const draftMarkdown = source.draftMarkdown ?? '';
const goal = source.goal ?? '';
const hook = source.primaryHook ?? `Most ${topic} projects look impressive in demos. They break when production pressure shows up.`;
const architectureSnapshot = source.architectureSnapshot ?? 'Input -> Planner -> Generator -> Validator -> Formatter -> Output';

const lines = draftMarkdown
  .split('\n')
  .map((line) => line.trim())
  .filter(Boolean);

const firstHeading = lines.find((line) => line.startsWith('# '));
const title = (firstHeading ? firstHeading.replace(/^#\s+/, '') : topic).trim();
const plainText = draftMarkdown
  .replace(/^#+\s+/gm, '')
  .replace(/```[\s\S]*?```/g, ' ')
  .replace(/`([^`]+)`/g, '$1')
  .replace(/[\*_>#-]/g, ' ')
  .replace(/\[(.*?)\]\((.*?)\)/g, '$1')
  .replace(/\s+/g, ' ')
  .trim();

const excerpt = plainText.slice(0, 220).trim() || `Deep dive on ${topic}`;
const metaDescription = plainText.slice(0, 155).trim() || `Technical guide about ${topic}`;
const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .trim()
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-');

const keywords = Array.from(new Set([
  topic,
  ...(Array.isArray(source.plan?.search_queries) ? source.plan.search_queries.slice(0, 4) : []),
  'agentic ai',
  'workflow automation',
  'ai automation'
].map((item) => String(item).trim()).filter(Boolean)));

const linkedinCaption = [
  hook,
  '',
  `The uncomfortable truth about ${topic}: most teams are still building polished demos, not dependable systems.`,
  '',
  `I wrote this for ${source.audience} because the real differentiator is not model access. It is execution discipline.`,
  '',
  'A few things I break down in the article:',
  `- where ${topic} pipelines usually fail first`,
  '- how agent handoffs should work in a real workflow',
  '- what retry logic and fallback behavior look like in practice',
  `- a concrete system flow: ${architectureSnapshot}`,
  `- why ${topic} behaves more like CI/CD for content than a single prompt call`,
  '',
  `One of the clearest signals in ${topic} right now is whether someone can turn ambiguity into architecture, workflows, and reliable output.`,
  '',
  goal || `The gap between demo ${topic} and production ${topic} is execution discipline.`,
  '',
  `Article title: ${title}`
].join('\n');

const toPascal = (value) => value
  .split(/[^a-zA-Z0-9]+/)
  .filter(Boolean)
  .map((part) => part.charAt(0).toUpperCase() + part.slice(1).toLowerCase())
  .join('');

const stopWords = new Set(['the', 'and', 'for', 'with', 'that', 'this', 'from', 'into', 'your', 'about', 'will', 'than', 'then', 'they', 'them', 'their', 'how', 'why', 'what', 'most', 'does', 'well', 'more', 'like', 'when', 'where']);
const phraseSources = [title, topic, ...keywords, ...(Array.isArray(source.plan?.search_queries) ? source.plan.search_queries : [])];
const hashtagCandidates = [];
const multiWordPatterns = [
  { regex: /agentic ai/gi, tag: 'AgenticAI' },
  { regex: /content pipelines?/gi, tag: 'ContentPipelines' },
  { regex: /workflow automation/gi, tag: 'WorkflowAutomation' },
  { regex: /ai engineering/gi, tag: 'AIEngineering' },
  { regex: /system design/gi, tag: 'SystemDesign' },
  { regex: /llm ops|llmops/gi, tag: 'LLMOps' },
  { regex: /software architecture/gi, tag: 'SoftwareArchitecture' },
  { regex: /state management/gi, tag: 'StateManagement' },
  { regex: /failure handling/gi, tag: 'FailureHandling' },
  { regex: /content workflow/gi, tag: 'ContentWorkflow' },
  { regex: /next\.?js|nextjs/gi, tag: 'Nextjs' },
  { regex: /\bn8n\b/gi, tag: 'n8n' },
];

for (const sourceText of phraseSources) {
  for (const pattern of multiWordPatterns) {
    if (pattern.regex.test(sourceText)) {
      hashtagCandidates.push(pattern.tag);
    }
  }

  const words = sourceText
    .toLowerCase()
    .split(/[^a-z0-9]+/)
    .filter((word) => word && word.length > 2 && !stopWords.has(word));

  for (let i = 0; i < words.length; i++) {
    hashtagCandidates.push(toPascal(words[i]));
    if (i < words.length - 1) {
      hashtagCandidates.push(toPascal(`${words[i]} ${words[i + 1]}`));
    }
  }
}

const linkedinHashtags = Array.from(new Set(hashtagCandidates))
  .filter((tag) => tag && tag.length >= 3 && tag.length <= 28)
  .slice(0, 10)
  .map((tag) => `#${tag}`);

const coverImagePrompt = `Create a premium LinkedIn blog cover for the topic "${title}". Visual style: editorial enterprise technology poster, dark graphite background, electric blue and steel highlights, clean architecture diagram feel, subtle node-and-edge workflow map, modern product system aesthetic, bold headline space, high-trust professional composition, designed to impress founders, clients, and hiring managers evaluating senior AI execution talent. Avoid cartoon styling, clutter, and generic stock-art visuals.`;

return [{
  json: {
    title,
    slug,
    excerpt,
    metaDescription,
    keywords,
    linkedinCaption,
    linkedinHashtags,
    coverImagePrompt,
    architectureSnapshot,
    viralHook: hook
  }
}];

let seo;

if ($json.title || $json.slug || $json.metaDescription) {
  seo = $json;
} else {
  const seoRaw = ($json.candidates?.[0]?.content?.parts ?? []).map((p) => p?.text ?? '').join('') || '{}';
  try {
    seo = JSON.parse(seoRaw);
  } catch {
    seo = {};
  }
}

const source = $item(0).$node['Collect Draft'].json;
const finalTitle = seo.title || source.topic;
const finalSlug = (seo.slug || source.topic)
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .trim()
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-');

return [{
  json: {
    success: true,
    generatedAt: new Date().toISOString(),
    title: finalTitle,
    slug: finalSlug,
    excerpt: seo.excerpt || `Deep dive on ${source.topic}`,
    metaDescription: seo.metaDescription || `Technical guide about ${source.topic}`,
    keywords: Array.isArray(seo.keywords) ? seo.keywords : [source.topic, 'agentic ai', 'workflow automation'],
    viralHook: seo.viralHook || source.primaryHook || `Most teams are still underestimating what it takes to build ${source.topic} well.`,
    linkedinCaption: seo.linkedinCaption || '',
    linkedinHashtags: Array.isArray(seo.linkedinHashtags) ? seo.linkedinHashtags : [],
    coverImagePrompt: seo.coverImagePrompt || '',
    architectureSnapshot: seo.architectureSnapshot || source.architectureSnapshot || source.plan?.architectureSnapshot || '',
    contentMarkdown: source.draftMarkdown,
    plan: source.plan,
    input: {
      topic: source.topic,
      audience: source.audience,
      tone: source.tone,
      wordCount: source.wordCount,
      cta: source.cta,
      goal: source.goal,
      proofPoints: source.proofPoints,
      systemExample: source.systemExample
    }
  }
}];
